using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
using namespace std;
int n, a, ans[50000][7];
int main(void)
{
	scanf("%d%d", &n, &a);
	ans[0][a % 7] = 1;
	for (register int i = 0; i < n - 1; ++i)
	{
		scanf("%d", &a);
		for (register int j = 0; j < 7; ++j)
			if (ans[i][j])
				ans[i + 1][(j + a) % 7] = ans[i][j] + 1;
		ans[i + 1][a % 7] = max(ans[i + 1][a % 7], 1);
	}
	int maxn = 0;
	for (register int i = 0; i < n; ++i)maxn = max(maxn, ans[i][0]);
	printf("%d", maxn);
}
